<?php
namespace App\Models;
use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\{BelongsTo,BelongsToMany};
class Booking extends Model { protected $fillable=['pnr','passenger_id','travel_route_id','travel_schedule_id','return_schedule_id','created_by','travel_date','return_date','status','total_amount','qr_code']; protected function casts(): array { return ['travel_date'=>'date','return_date'=>'date','total_amount'=>'decimal:2']; } public function passenger(): BelongsTo { return $this->belongsTo(Passenger::class); } public function route(): BelongsTo { return $this->belongsTo(TravelRoute::class,'travel_route_id'); } public function schedule(): BelongsTo { return $this->belongsTo(TravelSchedule::class,'travel_schedule_id'); } public function returnSchedule(): BelongsTo { return $this->belongsTo(TravelSchedule::class,'return_schedule_id'); } public function creator(): BelongsTo { return $this->belongsTo(User::class,'created_by'); } public function seats(): BelongsToMany { return $this->belongsToMany(Seat::class,'booking_seat')->withPivot('travel_schedule_id')->withTimestamps(); } }
